files.bench_support:
const DefaultScore: Int = 50;

@pure
fn classifySupport(score: Int) -> Text {
    if score >= 90 {
        ret "ready";
    }
    if score >= 70 {
        ret "review";
    }
    ret "blocked";
}

@pure
fn clampSupport(score: Int) -> Int {
    if score > 100 {
        ret 100;
    }
    if score < 0 {
        ret 0;
    }
    ret score;
}
